input.new_string:
async function gatherDecisionSignals(
  surreal: Surreal,
  workspaceRecord: RecordId<"workspace", string>,
  body?: Record<string, unknown>,
): Promise<DecisionSignals> {
  const status = (body?.status as string) ?? "unknown";
  const summary = (body?.summary as string) ?? "Unknown decision";
  const decisionId = (body?.id as RecordId)?.id as string | undefined
    ?? (body?.raw_id as string);

  if (!decisionId) {
    return { status, summary, completedTaskCount: 0 };
  }

  const decisionRecord = new RecordId("decision", decisionId);

  // Count completed tasks that share a project with this decision via belongs_to edges
  const [taskRows] = await surreal.query<[Array<{ count: number }>]>(
    `LET $projects = SELECT VALUE out FROM belongs_to WHERE in = $decision AND out.id.table = 'project';
     SELECT count() AS count FROM task
       WHERE workspace = $ws
         AND status IN ["completed", "done"]
         AND ->belongs_to->project CONTAINSANY $projects
       GROUP ALL;`,
    { decision: decisionRecord, ws: workspaceRecord },
  );

  return { status, summary, completedTaskCount: taskRows?.[0]?.count ?? 0 };
}

