  signals: DecisionSignals,
): VerificationResult {
  if (signals.status === "confirmed") {
    if (signals.completedTaskCount === 0) {
      return {
        verdict: "inconclusive",
        severity: "info",
        verified: false,
        text: `Decision confirmed: "${signals.summary}". No completed tasks found in related project(s).`,
      };
    }

    return {
      verdict: "match",
      severity: "info",
      verified: true,
      text: `Decision confirmed: "${signals.summary}". Found ${signals.completedTaskCount} completed task(s) in related project(s).`,
    };
  }

  if (signals.status === "superseded") {
    if (signals.completedTaskCount === 0) {
      return {
        verdict: "inconclusive",
        severity: "info",
        verified: false,
        text: `Decision superseded: "${signals.summary}". No completed tasks found that may be affected.`,
      };
    }

    return {
      verdict: "mismatch",
      severity: "warning",
      verified: false,
      text: `Decision superseded: "${signals.summary}". Found ${signals.completedTaskCount} completed task(s) in related project(s) that may now be based on an outdated decision. Review for staleness.`,
    };
